class Pointer:
 def __init__(self, value):
 self.value = value

 def __str__(self):
 return str(self.value)

var = 5
ptr = Pointer(var)
print("Value of var: ", var)
print("Address of var: ", id(var))
print("Value at address ptr: ", ptr)

#include <stdio.h>

int main() {
 int var = 5;
 int *ptr = &var;
 printf("Value of var: %d\n", var);
 printf("Address of var: %p\n", (void*)&var);
 printf("Value at address ptr: %d\n", *ptr);
 return 0;
}
